22	#include "Imaging.h"
23	
24	typedef struct {
25	    const void *table;
26	} im_point_context;
27	
28	static void
29	im_point_8_8(Imaging imOut, Imaging imIn, im_point_context *context) {
30	    int x, y;
31	    /* 8-bit source, 8-bit destination */
32	    UINT8 *table = (UINT8 *)context->table;
33	    for (y = 0; y < imIn->ysize; y++) {
34	        UINT8 *in = imIn->image8[y];
35	        UINT8 *out = imOut->image8[y];
36	        for (x = 0; x < imIn->xsize; x++) {
37	            out[x] = table[in[x]];
38	        }
39	    }
40	}
41	
42	static void
43	im_point_2x8_2x8(Imaging imOut, Imaging imIn, im_point_context *context) {
44	    int x, y;
45	    /* 2x8-bit source, 2x8-bit destination */
46	    UINT8 *table = (UINT8 *)context->table;
47	    for (y = 0; y < imIn->ysize; y++) {
48	        UINT8 *in = (UINT8 *)imIn->image[y];
49	        UINT8 *out = (UINT8 *)imOut->image[y];
50	        for (x = 0; x < imIn->xsize; x++) {
51	            out[0] = table[in[0]];
52	            out[3] = table[in[3] + 256];
53	            in += 4;
54	            out += 4;
55	        }
56	    }
57	}
58	
59	static void
60	im_point_3x8_3x8(Imaging imOut, Imaging imIn, im_point_context *context) {
61	    int x, y;
62	    /* 3x8-bit source, 3x8-bit destination */
63	    UINT8 *table = (UINT8 *)context->table;
64	    for (y = 0; y < imIn->ysize; y++) {
65	        UINT8 *in = (UINT8 *)imIn->image[y];
66	        UINT8 *out = (UINT8 *)imOut->image[y];
67	        for (x = 0; x < imIn->xsize; x++) {
68	            out[0] = table[in[0]];
69	            out[1] = table[in[1] + 256];
70	            out[2] = table[in[2] + 512];
71	            in += 4;
72	            out += 4;
73	        }
74	    }
75	}
