77	static void
78	im_point_4x8_4x8(Imaging imOut, Imaging imIn, im_point_context *context) {
79	    int x, y;
80	    /* 4x8-bit source, 4x8-bit destination */
81	    UINT8 *table = (UINT8 *)context->table;
82	    for (y = 0; y < imIn->ysize; y++) {
83	        UINT8 *in = (UINT8 *)imIn->image[y];
84	        UINT8 *out = (UINT8 *)imOut->image[y];
85	        for (x = 0; x < imIn->xsize; x++) {
86	            out[0] = table[in[0]];
87	            out[1] = table[in[1] + 256];
88	            out[2] = table[in[2] + 512];
89	            out[3] = table[in[3] + 768];
90	            in += 4;
91	            out += 4;
92	        }
93	    }
94	}
