96	static void
97	im_point_8_32(Imaging imOut, Imaging imIn, im_point_context *context) {
98	    int x, y;
99	    /* 8-bit source, 32-bit destination */
100	    char *table = (char *)context->table;
101	    for (y = 0; y < imIn->ysize; y++) {
102	        UINT8 *in = imIn->image8[y];
103	        INT32 *out = imOut->image32[y];
104	        for (x = 0; x < imIn->xsize; x++) {
105	            memcpy(out + x, table + in[x] * sizeof(INT32), sizeof(INT32));
106	        }
107	    }
108	}
109	
110	static void
111	im_point_32_8(Imaging imOut, Imaging imIn, im_point_context *context) {
112	    int x, y;
113	    /* 32-bit source, 8-bit destination */
114	    UINT8 *table = (UINT8 *)context->table;
115	    for (y = 0; y < imIn->ysize; y++) {
116	        INT32 *in = imIn->image32[y];
117	        UINT8 *out = imOut->image8[y];
118	        for (x = 0; x < imIn->xsize; x++) {
119	            int v = in[x];
120	            if (v < 0) {
121	                v = 0;
122	            } else if (v > 65535) {
123	                v = 65535;
124	            }
125	            out[x] = table[v];
126	        }
127	    }
128	}
