130	Imaging
131	ImagingPoint(Imaging imIn, const char *mode, const void *table) {
132	    /* lookup table transform */
133	
134	    ImagingSectionCookie cookie;
135	    Imaging imOut;
136	    im_point_context context;
137	    void (*point)(Imaging imIn, Imaging imOut, im_point_context * context);
138	
139	    if (!imIn) {
140	        return (Imaging)ImagingError_ModeError();
141	    }
142	
143	    if (!mode) {
144	        mode = imIn->mode;
145	    }
146	
147	    if (imIn->type != IMAGING_TYPE_UINT8) {
148	        if (imIn->type != IMAGING_TYPE_INT32 || strcmp(mode, "L") != 0) {
149	            goto mode_mismatch;
150	        }
151	    } else if (!imIn->image8 && strcmp(imIn->mode, mode) != 0) {
152	        goto mode_mismatch;
153	    }
154	
155	    imOut = ImagingNew(mode, imIn->xsize, imIn->ysize);
156	    if (!imOut) {
157	        return NULL;
158	    }
159	
160	    /* find appropriate handler */
161	    if (imIn->type == IMAGING_TYPE_UINT8) {
162	        if (imIn->bands == imOut->bands && imIn->type == imOut->type) {
163	            switch (imIn->bands) {
164	                case 1:
165	                    point = im_point_8_8;
166	                    break;
167	                case 2:
168	                    point = im_point_2x8_2x8;
169	                    break;
170	                case 3:
171	                    point = im_point_3x8_3x8;
172	                    break;
173	                case 4:
174	                    point = im_point_4x8_4x8;
175	                    break;
176	                default:
177	                    /* this cannot really happen */
178	                    point = im_point_8_8;
179	                    break;
180	            }
181	        } else {
182	            point = im_point_8_32;
183	        }
184	    } else {
185	        point = im_point_32_8;
186	    }
187	
188	    ImagingCopyPalette(imOut, imIn);
189	
190	    ImagingSectionEnter(&cookie);
191	
192	    context.table = table;
193	    point(imOut, imIn, &context);
194	
195	    ImagingSectionLeave(&cookie);
196	
197	    return imOut;
198	
199	mode_mismatch:
200	    return (Imaging)ImagingError_ValueError(
201	        "point operation not supported for this mode");
202	}
